import { Button } from "reactstrap";
import { capitalizeWords } from "../../../../../utils/toCapitalize";
import { Pencil } from "lucide-react";
import { format } from "date-fns";
import Highlighter from "react-highlight-words";

export const employeeReportingsColumns = ({
    onEdit,
    hasEditPermission,
    searchText
}) => [
        {
            name: <div>ECode</div>,
            selector: row => row?.employee?.eCode ?? "-",
            cell: row => (
                <Highlighter
                    highlightClassName="react-highlight"
                    searchWords={[searchText]}
                    autoEscape
                    textToHighlight={`${row.employee?.eCode || ""}`}
                />
            ),
            sortable: true,
            wrap: true,
        },
        {
            name: <div>Name</div>,
            selector: row => row?.employee?.name?.toUpperCase() ?? "-",
            cell: row => (
                <Highlighter
                    highlightClassName="react-highlight"
                    searchWords={[searchText]}
                    autoEscape
                    textToHighlight={`${row.employee?.name.toUpperCase() || ""}`}
                />
            ),
            wrap: true,
            minWidth: "160px",
        },
        {
            name: <div>Center</div>,
            cell: row =>
                row?.center?.title
                    ? capitalizeWords(row.center.title)
                    : "-",
            minWidth: "120px",
        },
        {
            name: "Manager",
            cell: row => {
                if (!row?.manager) return "-";

                const name = row.manager.name?.toUpperCase() || "";
                const eCode = row.manager.eCode || "-";

                return (
                    <span>
                        <Highlighter
                            highlightClassName="react-highlight"
                            searchWords={[searchText]}
                            autoEscape
                            textToHighlight={name}
                        />
                        {" "}
                        (
                        <Highlighter
                            highlightClassName="react-highlight"
                            searchWords={[searchText]}
                            autoEscape
                            textToHighlight={eCode}
                        />
                        )
                    </span>
                );
            },
            minWidth: "160px",
            wrap: true,
        },
        {
            name: "Shift",
            cell: row => {
                if (row?.shiftType === "ROTATIONAL") {
                    return <span>Rotational</span>;
                }
                return <span>{row?.shift ? `${capitalizeWords(row.shift)} (Fixed)` : "-"}</span>;
            },
            center: true,
            wrap: true,
        },
        {
            name: "Shift Timing/Date",
            cell: row => {
                if (row?.shiftType === "ROTATIONAL") {
                    const dates = (row.rotationalShifts || [])
                        .map(s => s.date)
                        .filter(Boolean)
                        .sort();
                    if (!dates.length) return "-";
                    const from = format(new Date(dates[0]), "dd MMM yy");
                    const to   = format(new Date(dates[dates.length - 1]), "dd MMM yy");
                    return <span style={{ fontSize: "11px" }}>{from} → {to}</span>;
                }
                return row?.timing ? `${row.timing.start} - ${row.timing.end}` : "-";
            },
            wrap: true,
            minWidth: "160px",
        },
        {
            name: <div>Active</div>,
            cell: row => row?.isActive ? "Yes" : "No",
            center: true,
            wrap: true
        },
        {
            name: <div>Assigned By</div>,
            selector: row => (
                <div>
                    <div>{capitalizeWords(row?.assignedBy?.name || "-")}</div>
                    <div style={{ fontSize: "12px", color: "#666" }}>
                        {row?.assignedBy?.email || "-"}
                    </div>
                </div>
            ),
            wrap: true,
            minWidth: "200px",
        },
        {
            name: <div>Start From</div>,
            selector: row => {
                const createdAt = row?.createdAt;
                if (!createdAt || isNaN(new Date(createdAt))) {
                    return "-"
                }
                return format(new Date(createdAt), "dd MMM yyyy, hh:mm a");
            },
            wrap: true,
            minWidth: "120px"
        },
        {
            name: <div>Ended At</div>,
            cell: row => {
                const endedAt = row?.endedAt;
                if (!endedAt || isNaN(new Date(endedAt))) {
                    return "-"
                }
                return format(new Date(endedAt), "dd MMM yyyy, hh:mm a");
            },
            minWidth: "120px"
        },
        {
            name: <div>Last Updated</div>,
            selector: row => {
                const lastChangedAt = row?.lastChangedAt;
                if (!lastChangedAt || isNaN(new Date(lastChangedAt))) {
                    return "-"
                }
                return format(new Date(lastChangedAt), "dd MMM yyyy, hh:mm a");
            },
            wrap: true,
            minWidth: "120px"
        },
        ...(hasEditPermission ? [
            {
                name: "Action",
                cell: row =>
                    row?.isActive ? (
                        <Button
                            color="outline-primary"
                            size="sm"
                            onClick={() => onEdit(row)}
                        >
                            <Pencil size={16} />
                        </Button>
                    ) : <i className="text-mutted">Action not permitted</i>,
                center: true,
                ignoreRowClick: true,
                allowOverflow: true,
                button: true,
            },
        ] : [])

    ];
